          code: `def findWords(board, words):
    # Build trie from words
    root = {}
    for word in words:
        node = root
        for char in word:
            node = node.setdefault(char, {})
        node['$'] = word  # Store word at end

    result = []
    rows, cols = len(board), len(board[0])

    def dfs(r, c, node):
        char = board[r][c]
        if char not in node:
            return

        next_node = node[char]

        # Found a word
        if '$' in next_node:
            result.append(next_node['$'])
            del next_node['$']  # Remove to avoid duplicates

        # Mark visited
        board[r][c] = '#'

        # Explore neighbors
        for dr, dc in [(0, 1), (0, -1), (1, 0), (-1, 0)]:
            nr, nc = r + dr, c + dc
            if 0 <= nr < rows and 0 <= nc < cols:
                dfs(nr, nc, next_node)

        # Restore
        board[r][c] = char

        # Prune: remove empty nodes
        if not next_node:
            del node[char]

    for r in range(rows):
        for c in range(cols):
            dfs(r, c, root)

    return result

# Time: O(m*n*4^L) where L is max word length`
