          code: `def mySqrt(x):
    """
    Binary search for largest k where k^2 <= x
    """
    if x < 2:
        return x

    left, right = 1, x // 2

    while left <= right:
        mid = left + (right - left) // 2
        square = mid * mid

        if square == x:
            return mid
        elif square < x:
            left = mid + 1
        else:
            right = mid - 1

    return right  # Largest k where k^2 <= x

# Time: O(log x), Space: O(1)
# Example: sqrt(8) = 2 (not 2.82...)

# Newton-Raphson (faster convergence):
def mySqrt_newton(x):
    if x < 2:
        return x
    r = x
    while r * r > x:
        r = (r + x // r) // 2
    return r`
