          code: `def gcd(a, b):
    """
    Euclidean Algorithm:
    gcd(a, b) = gcd(b, a % b) until b = 0

    Example: gcd(48, 18)
    48 % 18 = 12 → gcd(18, 12)
    18 % 12 = 6  → gcd(12, 6)
    12 % 6 = 0   → gcd(6, 0) = 6
    """
    while b:
        a, b = b, a % b
    return a

def lcm(a, b):
    """
    LCM formula: lcm(a,b) = a * b / gcd(a,b)
    Avoid overflow: a // gcd(a,b) * b
    """
    return a // gcd(a, b) * b

# Time: O(log min(a,b)), Space: O(1)

# Useful: GCD of array
def gcd_array(arr):
    from functools import reduce
    return reduce(gcd, arr)

# Example: gcd([12, 18, 24]) = 6`
